#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	int is_leaf;
	int num_keys;
} knode;

__kernel void 
findK(	long height,
		__global knode *knodesD,
		long knodes_elem,
		__global record *recordsD,

		__global long *currKnodeD,
		__global long *offsetD,
		__global int *keysD, 
		__global record *ansD)
{
	int thid = get_local_id(0);
	int bid = get_group_id(0);

	int i;
	for(i = 0; i < height; i++){
		long curr_knode_idx = currKnodeD[bid];
		if(curr_knode_idx >= knodes_elem) return;
		knode curr_knode = knodesD[curr_knode_idx];

		if((curr_knode.keys[thid] <= keysD[bid]) && (curr_knode.keys[thid+1] > keysD[bid])){
			long offset_idx = offsetD[bid];
			if(offset_idx < knodes_elem){
				knode offset_knode = knodesD[offset_idx];
				if(offset_knode.indices[thid] < knodes_elem){
					offsetD[bid] = offset_knode.indices[thid];
				}
			}
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		if(thid == 0){
			currKnodeD[bid] = offsetD[bid];
		}
		barrier(CLK_LOCAL_MEM_FENCE);
	}

	long curr_knode_idx = currKnodeD[bid];
	if(curr_knode_idx >= knodes_elem) return;
	knode curr_knode = knodesD[curr_knode_idx];

	if(curr_knode.keys[thid] == keysD[bid]){
		long rec_idx = curr_knode.indices[thid];
		if(rec_idx < knodes_elem){
			ansD[bid].value = recordsD[rec_idx].value;
		}
	}
}

