} knode;

__kernel void 
findRangeK(	long height,

			__global knode *knodesD,
			long knodes_elem,

			__global long *currKnodeD,
			__global long *offsetD,
			__global long *lastKnodeD,
			__global long *offset_2D,
			__global int *startD,
			__global int *endD,
			__global int *RecstartD, 
			__global int *ReclenD)
{
	int thid = get_local_id(0);
	int bid = get_group_id(0);

	int i;
	for(i = 0; i < height; i++){
		long curr_knode_idx = currKnodeD[bid];
		if(curr_knode_idx >= knodes_elem) return;
		knode curr_knode = knodesD[curr_knode_idx];

		if((curr_knode.keys[thid] <= startD[bid]) && (curr_knode.keys[thid+1] > startD[bid])){
			if(curr_knode.indices[thid] < knodes_elem){
				offsetD[bid] = curr_knode.indices[thid];
			}
		}

		long last_knode_idx = lastKnodeD[bid];
		if(last_knode_idx >= knodes_elem) return;
		knode last_knode = knodesD[last_knode_idx];

		if((last_knode.keys[thid] <= endD[bid]) && (last_knode.keys[thid+1] > endD[bid])){
			if(last_knode.indices[thid] < knodes_elem){
				offset_2D[bid] = last_knode.indices[thid];
			}
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		if(thid == 0){
			currKnodeD[bid] = offsetD[bid];
			lastKnodeD[bid] = offset_2D[bid];
		}
		barrier(CLK_LOCAL_MEM_FENCE);
	}

	long curr_knode_idx = currKnodeD[bid];
	if(curr_knode_idx >= knodes_elem) return;
	knode curr_knode = knodesD[curr_knode_idx];

	if(curr_knode.keys[thid] == startD[bid]){
		RecstartD[bid] = curr_knode.indices[thid];
	}
	barrier(CLK_LOCAL_MEM_FENCE);

	long last_knode_idx = lastKnodeD[bid];
	if(last_knode_idx >= knodes_elem) return;
	knode last_knode = knodesD[last_knode_idx];

	if(last_knode.keys[thid] == endD[bid]){
		ReclenD[bid] = last_knode.indices[thid] - RecstartD[bid] + 1;
	}
